import{_ as e,a,b as d,c as o,d as r,e as p}from"./chunks/查询额度成功.BKueuYqe.js";import{_ as s,o as l,c as i,a2 as n}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Добавление канала Dropbox","description":"","frontmatter":{},"headers":[],"relativePath":"ru-RU/upload/dropbox.md","filePath":"ru-RU/upload/dropbox.md","lastUpdated":1781962217000}'),c={name:"ru-RU/upload/dropbox.md"};function h(b,t,u,m,x,g){return l(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="добавление-канала-dropbox" tabindex="-1">Добавление канала Dropbox <a class="header-anchor" href="#добавление-канала-dropbox" aria-label="Permalink to &quot;Добавление канала Dropbox&quot;">​</a></h1><h2 id="что-подготовить-сначала" tabindex="-1">Что подготовить сначала <a class="header-anchor" href="#что-подготовить-сначала" aria-label="Permalink to &quot;Что подготовить сначала&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Что нужно</th><th>Зачем это нужно</th></tr></thead><tbody><tr><td>Аккаунт Dropbox</td><td>Для входа и авторизации app</td></tr><tr><td>Dropbox app</td><td>Для получения <code>App Key</code> и <code>App Secret</code></td></tr><tr><td>Ваш домен ImgBed</td><td>Для OAuth redirect URI</td></tr><tr><td>Доступное хранилище Dropbox</td><td>Фактическое место хранения файлов</td></tr></tbody></table><h2 id="настроика" tabindex="-1">Настройка <a class="header-anchor" href="#настроика" aria-label="Permalink to &quot;Настройка&quot;">​</a></h2><h3 id="шаг-1-создаите-dropbox-app" tabindex="-1">Шаг 1. Создайте Dropbox app <a class="header-anchor" href="#шаг-1-создаите-dropbox-app" aria-label="Permalink to &quot;Шаг 1. Создайте Dropbox app&quot;">​</a></h3><ol><li>Откройте Dropbox App Console:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.dropbox.com/developers/apps</span></span></code></pre></div><ol start="2"><li>Создайте новый app.</li><li>Для access type выберите:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>App folder</span></span></code></pre></div><ol start="4"><li>Дайте app понятное имя, например <code>imgbed-app</code>.</li><li>После создания откройте страницу деталей app.</li></ol><p>Рекомендуемый тип доступа:</p><table tabindex="0"><thead><tr><th>Access Type</th><th>Рекомендация</th></tr></thead><tbody><tr><td><code>App folder</code></td><td>Рекомендуется. Это соответствует тому, как ImgBed хранит файлы.</td></tr><tr><td><code>Full Dropbox</code></td><td>Не рекомендуется. ImgBed не нужен доступ ко всему аккаунту.</td></tr></tbody></table><p><img src="'+e+'" alt="Создание Dropbox app" loading="lazy"></p><h3 id="шаг-2-добавьте-redirect-uri" tabindex="-1">Шаг 2. Добавьте Redirect URI <a class="header-anchor" href="#шаг-2-добавьте-redirect-uri" aria-label="Permalink to &quot;Шаг 2. Добавьте Redirect URI&quot;">​</a></h3><p>На странице деталей Dropbox app найдите настройки OAuth или Redirect URI и добавьте:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/dropbox/callback</span></span></code></pre></div><p>Если админ-панель используется с нескольких доменов, добавьте каждый подходящий callback URL.</p><p><img src="'+a+'" alt="Настройка redirect URI" loading="lazy"></p><h3 id="шаг-3-настроите-permissions-app" tabindex="-1">Шаг 3. Настройте permissions app <a class="header-anchor" href="#шаг-3-настроите-permissions-app" aria-label="Permalink to &quot;Шаг 3. Настройте permissions app&quot;">​</a></h3><p>Откройте вкладку <code>Permissions</code> и включите как минимум такие scopes:</p><table tabindex="0"><thead><tr><th>Scope</th><th>Обязательно</th><th>Назначение</th></tr></thead><tbody><tr><td><code>account_info.read</code></td><td>Да</td><td>Читает информацию об аккаунте и квоте</td></tr><tr><td><code>files.metadata.read</code></td><td>Да</td><td>Читает метаданные файлов и папок для проверки путей</td></tr><tr><td><code>files.metadata.write</code></td><td>Да</td><td>Создает папки и записывает метаданные</td></tr><tr><td><code>files.content.write</code></td><td>Да</td><td>Загружает файлы. Без этого scope будет ошибка <code>required scope &#39;files.content.write&#39;</code>.</td></tr><tr><td><code>files.content.read</code></td><td>Рекомендуется</td><td>Позволяет скачивание, preview и временные ссылки на файлы</td></tr></tbody></table><p>После выбора scopes нажмите <code>Submit</code> внизу страницы.</p><p><img src="'+d+'" alt="Добавление прав" loading="lazy"></p><p>Важно:</p><table tabindex="0"><thead><tr><th>Ситуация</th><th>Что сделать</th></tr></thead><tbody><tr><td>Вы изменили scopes</td><td>Запустите authorization flow заново и получите новый <code>Refresh Token</code>.</td></tr><tr><td>Вы не авторизовались повторно</td><td>Старый token не получит новые permissions, поэтому загрузка все еще может падать.</td></tr></tbody></table><h3 id="шаг-4-скопируите-credentials-app" tabindex="-1">Шаг 4. Скопируйте credentials app <a class="header-anchor" href="#шаг-4-скопируите-credentials-app" aria-label="Permalink to &quot;Шаг 4. Скопируйте credentials app&quot;">​</a></h3><p>Сохраните два значения со страницы Dropbox app:</p><table tabindex="0"><thead><tr><th>Поле Dropbox</th><th>Поле ImgBed</th></tr></thead><tbody><tr><td><code>App key</code></td><td><code>App Key</code></td></tr><tr><td><code>App secret</code></td><td><code>App Secret</code></td></tr></tbody></table><h3 id="шаг-5-заполните-канал-dropbox" tabindex="-1">Шаг 5. Заполните канал Dropbox <a class="header-anchor" href="#шаг-5-заполните-канал-dropbox" aria-label="Permalink to &quot;Шаг 5. Заполните канал Dropbox&quot;">​</a></h3><p>В настройках загрузки выберите <code>Dropbox</code> и заполните:</p><table tabindex="0"><thead><tr><th>Поле ImgBed</th><th>Что ввести</th></tr></thead><tbody><tr><td>Channel name</td><td>Понятное имя, например <code>Main Dropbox</code></td></tr><tr><td>App Key</td><td>Dropbox <code>App key</code></td></tr><tr><td>App Secret</td><td>Dropbox <code>App secret</code></td></tr><tr><td>Refresh Token</td><td>Пока оставьте пустым</td></tr><tr><td>Root directory</td><td>Необязательно. По умолчанию <code>imgbed</code>.</td></tr><tr><td>Note</td><td>Необязательно</td></tr></tbody></table><p><img src="'+o+'" alt="Получение token" loading="lazy"></p><h3 id="шаг-6-получите-refresh-token" tabindex="-1">Шаг 6. Получите Refresh Token <a class="header-anchor" href="#шаг-6-получите-refresh-token" aria-label="Permalink to &quot;Шаг 6. Получите Refresh Token&quot;">​</a></h3><ol><li>В ImgBed нажмите <code>Get Token</code>.</li><li>Войдите в Dropbox-аккаунт, который хотите подключить.</li><li>Подтвердите запрос авторизации.</li><li>На callback-странице появится <code>Refresh Token</code>.</li><li>Скопируйте его.</li><li>Вернитесь в ImgBed и вставьте его в поле <code>Refresh Token</code>.</li></ol><p><img src="'+r+'" alt="Копирование token" loading="lazy"></p><h2 id="как-проверить" tabindex="-1">Как проверить <a class="header-anchor" href="#как-проверить" aria-label="Permalink to &quot;Как проверить&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Проверка</th><th>Ожидаемый результат</th></tr></thead><tbody><tr><td>Карточка канала</td><td>Dropbox-канал появляется после сохранения.</td></tr><tr><td>Переключатель канала</td><td>Канал можно включить.</td></tr><tr><td>Token сохранен</td><td>На странице деталей видно, что <code>Refresh Token</code> сохранен.</td></tr><tr><td>Тестовая загрузка</td><td>Тестовое изображение появляется в app folder Dropbox.</td></tr></tbody></table><p>Если включены quota limits, нажмите запрос квоты. После успешного запроса карточка канала показывает использованный объем, общий объем и время последнего обновления.</p><p><img src="'+p+`" alt="Успешный запрос квоты" loading="lazy"></p><h2 id="устранение-неполадок" tabindex="-1">Устранение неполадок <a class="header-anchor" href="#устранение-неполадок" aria-label="Permalink to &quot;Устранение неполадок&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Проблема</th><th>Как исправить</th></tr></thead><tbody><tr><td>ImgBed сообщает, что конфигурация неполная</td><td>Проверьте, что <code>App Key</code>, <code>App Secret</code> и <code>Refresh Token</code> все заполнены.</td></tr><tr><td>Авторизация успешна, но <code>Refresh Token</code> не появляется</td><td>Нажмите <code>Get Token</code> еще раз и убедитесь, что используется offline authorization flow.</td></tr><tr><td>Загрузка падает с <code>required scope &#39;files.content.write&#39;</code></td><td>Включите <code>files.content.write</code>, нажмите <code>Submit</code>, затем получите новый <code>Refresh Token</code>.</td></tr><tr><td>Callback не проходит</td><td>Убедитесь, что redirect URI имеет вид <code>https://your-domain.com/api/oauth/dropbox/callback</code>.</td></tr><tr><td>Файлы не находятся</td><td>Убедитесь, что Dropbox app создан в режиме <code>App folder</code>.</td></tr></tbody></table><h2 id="короткии-сценарии" tabindex="-1">Короткий сценарий <a class="header-anchor" href="#короткии-сценарии" aria-label="Permalink to &quot;Короткий сценарий&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Открыть Dropbox App Console</span></span>
<span class="line"><span>-&gt; Создать app</span></span>
<span class="line"><span>-&gt; Выбрать App folder access</span></span>
<span class="line"><span>-&gt; Добавить https://your-domain.com/api/oauth/dropbox/callback</span></span>
<span class="line"><span>-&gt; Включить account_info.read / files.metadata.read / files.metadata.write / files.content.write</span></span>
<span class="line"><span>-&gt; При желании включить files.content.read</span></span>
<span class="line"><span>-&gt; Нажать Submit</span></span>
<span class="line"><span>-&gt; Скопировать App Key и App Secret</span></span>
<span class="line"><span>-&gt; Ввести их в ImgBed</span></span>
<span class="line"><span>-&gt; Нажать Get Token</span></span>
<span class="line"><span>-&gt; Скопировать Refresh Token с callback-страницы</span></span>
<span class="line"><span>-&gt; Вставить его обратно в ImgBed и сохранить</span></span></code></pre></div><h2 id="ссылки" tabindex="-1">Ссылки <a class="header-anchor" href="#ссылки" aria-label="Permalink to &quot;Ссылки&quot;">​</a></h2><ol><li>Dropbox App Console: <a href="https://www.dropbox.com/developers/apps" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/apps</a></li><li>Dropbox OAuth Guide: <a href="https://developers.dropbox.com/oauth-guide" target="_blank" rel="noreferrer">https://developers.dropbox.com/oauth-guide</a></li><li>Dropbox Developer Guide: <a href="https://www.dropbox.com/developers/reference/developer-guide" target="_blank" rel="noreferrer">https://www.dropbox.com/developers/reference/developer-guide</a></li></ol>`,45)])])}const _=s(c,[["render",h]]);export{y as __pageData,_ as default};
